def generate_powerset(list):
 powerset = []
 for i in range(2**len(list)):
  subset = [list[bit] for bit in range(len(list)) if is_bit_set(i, bit)]
  powerset.append(subset)
 return powerset

def is_bit_set(num, bit):
 return (num & (1 << bit)) != 0

