function getMedian(arr) {
  arr.sort(function (a, b) {
    return a - b;
  });

  let mid = Math.floor(arr.length / 2);

  if (arr.length % 2 === 0) {
    return (arr[mid - 1] + arr[mid]) / 2;
  } else {
    return arr[mid];
  }
}

