def longest_palindrome(string):
    palindrome = ''
    for i in range(len(string)):
        for j in range(i+1, len(string)+1):
            substring = string[i:j]
            if substring == substring[::-1] and len(substring) > len(palindrome):
                palindrome = substring
    return palindrome

